diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 756b25ac9856..7e4ab204b7b5 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -20995,6 +20995,18 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
         Bundle[BundleIndex++] = GEPIdx;
       }

+      // Check that all indices are defined in the same basic block.
+      // SLP vectorizer works within a basic block.
+      if (!Bundle.empty()) {
+        auto *FirstInst = dyn_cast<Instruction>(Bundle[0]);
+        if (FirstInst) {
+          BasicBlock *FirstBB = FirstInst->getParent();
+          if (!all_of(Bundle, [FirstBB](Value *V) {
+                return !isa<Instruction>(V) || cast<Instruction>(V)->getParent() == FirstBB;
+              }))
+            continue;
+        }
+      }
